patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
index 4a014ab6e044..7800fbadfd3a 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineShifts.cpp
@@ -1561,6 +1561,17 @@ Instruction *InstCombinerImpl::visitLShr(BinaryOperator &I) {
       Value *And = Builder.CreateAnd(BoolX, BoolY);
       return new ZExtInst(And, Ty);
     }
+
+    // Reduce add-carry of masked LSBs to logic:
+    // ((X & 1) + (Y & 1)) >> 1 --> (Y & 1) & X
+    // This computes the average of two LSBs, which is equivalent to AND.
+    Value *AndOp0, *AndOp1;
+    if (ShAmtC == 1 && match(Op0, m_Add(m_Value(X), m_Value(Y))) &&
+        match(X, m_OneUse(m_And(m_Value(AndOp0), m_One()))) &&
+        match(Y, m_OneUse(m_And(m_Value(AndOp1), m_One())))) {
+      Value *And = Builder.CreateAnd(Y, AndOp0);
+      return replaceInstUsesWith(I, And);
+    }
   }

   const SimplifyQuery Q = SQ.getWithInstruction(&I);

